   238→					dn, LDAP_AUTH_SASL, mechanism, cred);
   239→			} else {
   240→				rc = ber_printf(ber, "{st{sON}" /*"}"*/,
   241→					dn, LDAP_AUTH_SASL, mechanism, cred);
   242→			}
   243→		}
   244→	}
   245→
   246→	if (rc < 0) {
   247→		rc = ld->ld_errno = LDAP_ENCODING_ERROR;
   248→		goto done;
   249→	}
   250→
   251→	if (vcctrls && *vcctrls) {
   252→		LDAPControl *const *c;
