   290→int
   291→ldap_verify_credentials_s(
   292→	LDAP *ld,
   293→	struct berval	*cookie,
   294→	LDAP_CONST char *dn,
   295→	LDAP_CONST char *mechanism,
   296→	struct berval	*cred,
   297→    LDAPControl		**vcictrls,
   298→	LDAPControl		**sctrls,
   299→	LDAPControl		**cctrls,
